sparql:
SELECT(COUNT(?game) AS ?total) WHERE {
  VALUES ?label {
    "1982 National League Championship Series" @en "2006 National League Championship Series" @en "2011 World Series" @en "2013 National League Championship Series" @en "2011 National League Championship Series" @en
  }
  ?series rdfs:label ?label .
  ?series wdt:P586 wd:Q54347 .
  ?game wdt:P155 ?series .
}

SELECT(MAX(?attendance) AS ?max_attendance) WHERE {
  {
    ?series wdt:P31 wd:Q253586 ; rdfs:label "2018 World Series" @en .
    ?game wdt:P121 ?series ; wdt:P186 wd:Q11833 ; wdt:P2515 ?attendance .
  } UNION {
    ?series wdt:P31 wd:Q333619 ; rdfs:label "2013 American League Championship Series" @en .
    ?game wdt:P121 ?series ; wdt:P186 wd:Q11833 ; wdt:P2515 ?attendance .
  } UNION {
    ?series wdt:P31 wd:Q333619 ; rdfs:label "1975 American League Championship Series" @en .
    ?game wdt:P121 ?series ; wdt:P186 wd:Q11833 ; wdt:P2515 ?attendance .
  }
}

SELECT(MAX(?numRaces) - MIN(?numRaces) AS ?difference) {
  ?season wdt:P31 wd:Q498916 ; wdt:P191 wd:Q155383 ; wdt:P154 wd:Q1524788 ; wdt:P7233 ?numRaces .
}

SELECT ?team WHERE {
  ?team rdfs:label "St. Louis Cardinals" @en .
}

SELECT(COUNT(*) AS ?count) WHERE {
  {
    ?series wdt:P31 wd:Q131058 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 1975)
    ?game wdt:P1545 ?series ; wdt:P1366 wd:Q6297 ; wdt:P619 wd:Q1347351
  } UNION {
    ?series wdt:P31 wd:Q131058 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 2013)
    ?game wdt:P1545 ?series ; wdt:P1366 wd:Q6297 ; wdt:P619 wd:Q1347351
  } UNION {
    ?series wdt:P31 wd:Q1740123 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 2018)
    ?game wdt:P1545 ?series ; wdt:P1366 wd:Q6297 ; wdt:P619 wd:Q1347351
  }
}

SELECT(COUNT(DISTINCT ?runnerup) AS ?count) WHERE {
  ?event wdt:P31 wd:Q2223175 ; wdt:P275 wd:Q105487 ; wdt:P1449 wd:Q453300 ; wdt:P116 ?runnerup .
  FILTER(?runnerup != wd:Q453300)
}

SELECT(COUNT(*) AS ?count) WHERE {
  VALUES ?series {
    wd:Q45330062 wd:Q20334965 wd:Q22205788
  }
  ?game wdt:P1343 ?series ; wdt:P276 wd:Q47152 .
}

SELECT(MAX(?attendance) AS ?max) WHERE {
  VALUES ?series {
    wd:Q260596 wd:Q13466679 wd:Q26510564
  }
  ?game wdt:P2565 ?series ; wdt:P1340 wd:Q1291911 ; wdt:P3755 ?attendance .
}

SELECT(MAX(?grandFinals) AS ?maxGrandFinals) WHERE {
  VALUES ?club {
    wd:Q165869 wd:Q453300
  }
  ?club wdt:P1332 ?grandFinals .
}

SELECT(MAX(?appearances) AS ?maxAppearances) WHERE {
  VALUES ?club {
    wd:Q31710 wd:Q174877
  }
  ?club wdt:P3624 ?appearances .
}

SELECT(SUM(?attendance) AS ?total) WHERE {
  {
    ?game wdt:P551 wd:Q51744098 ; wdt:P1064 wd:Q16644 ; wdt:P5484 ?attendance .
  } UNION {
    ?game wdt:P551 wd:Q24424109 ; wdt:P1064 wd:Q16644 ; wdt:P5484 ?attendance .
  } UNION {
    ?game wdt:P551 wd:Q12566951 ; wdt:P1064 wd:Q16644 ; wdt:P5484 ?attendance .
  }
}

SELECT(MIN(?appearances) AS ?lowest) WHERE {
  VALUES ?club {
    wd:Q524131 wd:Q619142
  }
  ?club wdt:P3270 ?appearances
}

SELECT(SUM(?numRaces) AS ?total) WHERE {
  ?season wdt:P31 wd:Q1796632 ; wdt:P523 wd:Q431 ; wdt:P524 wd:Q704 ; wdt:P2168 ?numRaces .
}

SELECT(SUM(?games) AS ?totalGames) WHERE {
  ?series wdt:P31 wd:Q5605523 ; wdt:P585 ?date ; wdt:P1545 ?games .
  ?series wdt:P1887 wd:Q18397 .
  ?series wdt:P1887 wd:Q104153 .
  BIND(SUBSTR(STR(?date) , 1 , 4) AS ?year)
  VALUES ?year {
    "1977" "1978" "2008" "2009"
  }
}

SELECT(SUM(?games) AS ?total) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?nlcs wdt:P31 wd:Q25484 ; wdt:P585 ?eventDate ; wdt:P795 ?games .
  FILTER(year(?eventDate) IN(1977 , 1978 , 2008 , 2009))
  ?nlcs p:P126 ?stmt1 .
  ?stmt1 ps:P126 wd:Q26350 .
  ?nlcs p:P126 ?stmt2 .
  ?stmt2 ps:P126 wd:Q26535 .
  FILTER(?stmt1 != ?stmt2)
}

SELECT(MAX(?att) AS ?maxAttendance) WHERE {
  {
    ?series wdt:P31 wd:Q7460980 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 1975)
    ?game wdt:P1343 ?series .
    ?game wdt:P1126 ?att .
  } UNION {
    ?series wdt:P31 wd:Q7460980 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 2013)
    ?game wdt:P1343 ?series .
    ?game wdt:P1126 ?att .
  } UNION {
    ?series wdt:P31 wd:Q550219 ; wdt:P585 ?date .
    FILTER(YEAR(?date) = 2018)
    ?game wdt:P1343 ?series .
    ?game wdt:P1126 ?att .
  }
}

SELECT(SUM(?games) AS ?total_games) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?series wdt:P31 wd:Q2849142 ; wdt:P463 wd:Q12277 ; wdt:P463 wd:Q3776 ; wdt:P585 ?date ; wdt:P1546 ?games .
  FILTER(year(?date) = ?year)
}

SELECT(SUM(?games) AS ?total) WHERE {
  VALUES ?eventType {
    wd:Q246339 wd:Q1019872
  }
  ?series wdt:P31 ?eventType .
  ?series wdt:P1542 wd:Q14683 .
  ?series wdt:P3475 ?games .
}

SELECT(SUM(?games) AS ?total) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?series wdt:P31 wd:Q897381 .
  ?series wdt:P585 ?time .
  ?time wikibase:timeYear ?year .
  ?series wdt:P1150 ?games .
  ?series wdt:P1058 wd:Q35107 .
  ?series wdt:P1058 wd:Q24449 .
}

SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  {
    ?series rdfs:label "2018 World Series" @en ; wdt:P31 wd:Q468893 .
    ?game wdt:P1545 ?series .
    ?game wdt:P525 ?attendance .
  } UNION {
    ?series rdfs:label "2013 American League Championship Series" @en ; wdt:P31 wd:Q1909334 .
    ?game wdt:P1545 ?series .
    ?game wdt:P525 ?attendance .
  } UNION {
    ?series rdfs:label "1975 American League Championship Series" @en ; wdt:P31 wd:Q1909334 .
    ?game wdt:P1545 ?series .
    ?game wdt:P525 ?attendance .
  }
}

SELECT(SUM(?numGames) AS ?total) WHERE {
  {
    ?series rdfs:label "1975 American League Championship Series" @en ; wdt:P1350 ?numGames .
  } UNION {
    ?series rdfs:label "2013 American League Championship Series" @en ; wdt:P1350 ?numGames .
  } UNION {
    ?series rdfs:label "2018 World Series" @en ; wdt:P1350 ?numGames .
  }
}

SELECT(COUNT(*) AS ?count) WHERE {
  ?grand_final wdt:P31 wd:Q2203483 .
  {
    ?grand_final wdt:P58 ?team .
    VALUES ?team {
      wd:Q426350 wd:Q441720
    }
  } UNION {
    ?grand_final wdt:P59 ?team .
    VALUES ?team {
      wd:Q426350 wd:Q441720
    }
  }
}

SELECT(SUM(?games) AS ?total) WHERE {
  {
    ?series wdt:P31 wd:Q5369482 ; wdt:P571 ?date ; wdt:P137 wd:Q155010 ; wdt:P1181 ?games .
    FILTER(STRSTARTS(STR(?date) , "1975"))
  } UNION {
    ?series wdt:P31 wd:Q5369482 ; wdt:P571 ?date ; wdt:P137 wd:Q155010 ; wdt:P1181 ?games .
    FILTER(STRSTARTS(STR(?date) , "2013"))
  } UNION {
    ?series wdt:P31 wd:Q352923 ; wdt:P571 ?date ; wdt:P137 wd:Q155010 ; wdt:P1181 ?games .
    FILTER(STRSTARTS(STR(?date) , "2018"))
  }
}

SELECT(COUNT(?game) AS ?count) WHERE {
  ?game wdt:P31 wd:Q3398510 ; wdt:P191 wd:Q11237 ; wdt:P192 wd:Q108995 ; wdt:P187 wd:Q191262 ; wdt:P585 ?eventDate ;
  FILTER(YEAR(?eventDate) >= 1977 && YEAR(?eventDate) <= 2009)
}

SELECT(COUNT(*) AS ?total) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?game wdt:P1545 ?series .
  ?game wdt:P286 wd:Q22019 .
}

SELECT(COUNT(*) AS ?total_games) WHERE {
  {
    ?series wdt:P31 wd:Q303988 ; wdt:P580 ?year .
    FILTER(YEAR(?year) = 1975)
    ?game wdt:P1548 ?series ; wdt:P178 wd:Q152619 .
  } UNION {
    ?series wdt:P31 wd:Q303988 ; wdt:P580 ?year .
    FILTER(YEAR(?year) = 2013)
    ?game wdt:P1548 ?series ; wdt:P178 wd:Q152619 .
  } UNION {
    ?series wdt:P31 wd:Q7329 ; wdt:P580 ?year .
    FILTER(YEAR(?year) = 2018)
    ?game wdt:P1548 ?series ; wdt:P178 wd:Q152619 .
  }
}

SELECT(SUM(?games) AS ?total) {
  {
    ?event rdfs:label "1975 American League Championship Series" @en ; wdt:P1350 ?games .
  } UNION {
    ?event rdfs:label "2013 American League Championship Series" @en ; wdt:P1350 ?games .
  } UNION {
    ?event rdfs:label "2018 World Series" @en ; wdt:P1350 ?games .
  }
}

SELECT(SUM(?games) AS ?total) WHERE {
  ?event wdt:P31 wd:Q3531707 ; wdt:P771 wd:Q513773 ; wdt:P771 wd:Q95198 ; wdt:P585 ?date ; wdt:P2262 ?games .
  FILTER(year(?date) = 2008)
}

SELECT(COUNT(*) AS ?total) WHERE {
  VALUES ?club {
    wd:Q2410232 wd:Q553228
  }
  ?event wdt:P31 wd:Q2959824 ; wdt:P100 ?club ; wdt:P122 ?winner .
  FILTER(?club != ?winner)
}

SELECT(COUNT(?game) AS ?count) WHERE {
  ?series wdt:P31 wd:Q7655986 ; wdt:P354 wd:Q15125 ; wdt:P354 wd:Q48205 .
  ?game wdt:P120 ?series .
  ?game wdt:P150 ?venue .
  ?venue wdt:P131 wd:Q23051 .
}

SELECT(COUNT(?richmond_year) AS ?count) WHERE {
  {
    SELECT(MIN(?collingwood_year) AS ?min_year) WHERE {
      ?season wdt:P718 wd:Q33313 ; wdt:P31 wd:Q118458 ; wdt:P527 wd:Q551729 ; wdt:P585 ?collingwood_year .
    }
  }
  ?season wdt:P718 wd:Q31392 ; wdt:P31 wd:Q118458 ; wdt:P527 wd:Q551729 ; wdt:P585 ?richmond_year .
  FILTER(?richmond_year > ?min_year)
}

SELECT(COUNT(DISTINCT ?driver) AS ?uniqueCount) WHERE {
  {
    wd:Q1054748 wdt:P1654 ?driver
  } UNION {
    wd:Q2532496 wdt:P1655 ?driver
  }
}

SELECT(COUNT(DISTINCT ?team) AS ?count) WHERE {
  ?season wdt:P2112 wd:Q515543 ; wdt:P155 wd:Q171725 ; wdt:P150 ?team .
}

SELECT(SUM(?races) AS ?totalRaces) WHERE {
  wd:Q40127 wdt:P1050 ?championship .
  ?championship wdt:P2353 ?season .
  ?season wdt:P585 ?date .
  ?season wdt:P1404 ?races .
  BIND(SUBSTR(STR(?date) , 1 , 4) AS ?year)
  {
    SELECT(MIN(?year) AS ?minYear) {
      wd:Q40127 wdt:P1050 ?championship .
      ?championship wdt:P2353 ?season .
      ?season wdt:P585 ?date .
      BIND(SUBSTR(STR(?date) , 1 , 4) AS ?year)
    }
  }
  {
    SELECT(MAX(?year) AS ?maxYear) {
      wd:Q40127 wdt:P1050 ?championship .
      ?championship wdt:P2353 ?season .
      ?season wdt:P585 ?date .
      BIND(SUBSTR(STR(?date) , 1 , 4) AS ?year)
    }
  }
  FILTER(?year = ?minYear || ?year = ?maxYear)
}

SELECT(MAX(?year) - MIN(?year) AS ?difference) WHERE {
  ?nls wdt:P31 wd:Q508922 .
  ?nls wdt:P1772 ?year .
  ?nls wdt:P1334 wd:Q21852 .
  ?nls wdt:P1334 wd:Q37134 .
}
